@import (reference) "../style/themes/default.less";

.am-vtabs {
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: row;

  &-bar {
    width: @size-15 * 2;
    overflow: hidden;
    &-line {
      position: absolute;
      left: 0;
      top: @h-spacing-large;
      bottom: @h-spacing-large;
      width: 6 * @pixelSize;
      overflow: hidden;
      font-size: 0;
      border-radius: @corner-radius-circle;
      &-radius {
        position: absolute;
        right: 0;
        width: @size-2;
        height: @size-2;
        border-radius: @corner-radius-circle;
        overflow: hidden;
        font-size: 0;
        &__top {
          top: -@size-2;
        }
        &__bottom {
          bottom: -@size-2;
        }
      }
    }
    &-placehold {
      flex: 1 1 0%;
    }
  }

  &-bar-content {
    display: flex;
    flex-direction: column;
    height: 100%;
    width: @size-15 * 2;
    &::-webkit-scrollbar {
      display: none;
    }
  }

  &-bar-tab {
    position: relative;
    box-sizing: border-box;
    width: @size-15 * 2;
    padding: @h-spacing-large @size-6;
    text-align: center;
    &__hover {
      opacity: 0.6;
    }
    &__active {
      font-size: @font-size-subtitle;
      font-size: var(--am-vtabs-fontSize-active, @font-size-subtitle);
    }
    &__same {
      font-size: @font-size-content;
      font-size: var(--am-vtabs-fontSize-same, @font-size-content);
    }
  }

  &-bar-title {
    position: relative;
    display: inline-block;
  }

  &-content-wrap {
    overflow: hidden;
    flex: 1;
    height: 100%;
    background-color: @color-fill-grey-inverse;
    background-color: var(--am-vtabs-content-bgc, @color-fill-grey-inverse);
  }

  &-slides {
    height: 100%;
  }

  &-slides.animate {
    transition-duration: 300ms;
  }
}

// Cascader
// --------------------------------------------------
@prefix-cls-cascader: e("@{prefix-cls}-cascader");

.@{prefix-cls-cascader} {
  position: relative;
  display: inline-block;
}
.@{prefix-cls-cascader}-picker {
  position: relative;
  display: inline-block;
  cursor: pointer;
  vertical-align: middle;
}
.@{prefix-cls-cascader}-menus {
  font-size: 12px;
  background: #fff;
  border: 1px solid #d9d9d9;
  border-radius: 6px;
  box-shadow: 0 0 4px rgba(0, 0, 0, 0.17);
  white-space: nowrap;
}
.@{prefix-cls-cascader}-menu {
  display: inline-block;
  vertical-align: top;
  min-width: 111px;
  height: 180px;
  list-style: none;
  margin: 0;
  padding: 0;
  border-right: 1px solid #d9d9d9;
  overflow: auto;
}

.@{prefix-cls-cascader}-menu:last-child {
  border-right-color: transparent;
  margin-right: -1px
}

.@{prefix-cls-cascader}-menu-item {
  padding: 7px 16px;
  cursor: pointer;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  transition: all .3s ease;
  &:hover, &:focus {
    background-color: tint(@primary-color, 95%);
  }
  &.@{prefix-cls-cascader}-selected {
    &,
    &:hover,
    &:focus {
      outline: 0;
      color: #fff;
      background-color: tint(@primary-color, 40%);
    }
  }

  &.@{prefix-cls-cascader}-disabled {
    cursor: not-allowed;
    color: #ccc;
  }
  &.@{prefix-cls-cascader}-disabled:hover {
    background: transparent;
  }
}

.@{prefix-cls-cascader}-menu-item-expand {
    position: relative;
}

.@{prefix-cls-cascader}-menu-item-expand:after {
    content: '\E600';
    font-family: 'anticon';
    display: inline-block;
    font-size: 12px;
    transform: scale(.66666667) rotate(0deg);
    -ms-filter: "progid:DXImageTransform.Microsoft.Matrix(sizingMethod='auto expand', M11=1, M12=0, M21=0, M22=1)";
    zoom: 1;
    color: #999;
    position: absolute;
    right: 15px;
}

@class-prefix-image-uploader: ~'adm-image-uploader';

.@{class-prefix-image-uploader} {
  --cell-size: 80px;
  --gap: 12px;
  ---gap: var(--gap);
  ---gap-horizontal: var(--gap-horizontal, var(--gap));
  ---gap-vertical: var(--gap-vertical, var(--gap));

  &-grid,
  &-space {
    --gap: var(---gap);
    --gap-horizontal: var(---gap-horizontal);
    --gap-vertical: var(---gap-vertical);
  }

  &-cell {
    position: relative;
    width: var(--cell-size);
    height: var(--cell-size);
    border-radius: 4px;
    overflow: hidden;

    &-fail {
      border: red solid 1px;
      box-sizing: border-box;
    }

    &-delete {
      position: absolute;
      top: 0;
      right: 0;
      width: 14px;
      height: 14px;
      background-color: rgba(0, 0, 0, 0.7);
      border-radius: 0 0 0 12px;
      font-size: 8px;
      color: var(--adm-color-white);
      cursor: pointer;
      &-icon {
        position: absolute;
        left: 4px;
        top: 3px;
      }
    }

    &-mask {
      position: absolute;
      top: 0;
      right: 0;
      bottom: 0;
      left: 0;
      color: var(--adm-color-white);
      background-color: rgba(50, 50, 51, 0.88);
    }

    &-loading {
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      height: 100%;
      box-sizing: border-box;
      padding-top: 8px;
    }

    &-mask-message {
      display: inline-block;
      padding: 6px 4px;
      font-size: var(--adm-font-size-4);
    }

    &-image {
      width: var(--cell-size);
      height: var(--cell-size);
    }
  }

  &-upload-button-wrap {
    position: relative;

    .@{class-prefix-image-uploader}-upload-button {
      background-color: var(--adm-color-box);
      text-align: center;
      line-height: var(--cell-size);
      display: block;

      &-icon {
        color: var(--adm-color-weak);
        font-size: 32px;
      }
    }
    .@{class-prefix-image-uploader}-input {
      cursor: pointer;
      position: absolute;
      opacity: 0;
      left: 0;
      top: 0;
      width: 100%;
      height: 100%;
      border-radius: 4px;
    }
  }

  .@{class-prefix-image-uploader}-gap-measure {
    position: absolute;
    left: 0;
    top: 0;
    height: var(--gap-horizontal);
    width: 0;
  }
}

@class-prefix-button: ~'adm-button';

.adm-button {
  color: #333333;
  background-color: #ffffff;
  font-size: 17px;
  border-width: 1px;
  border-style: solid;
  border-color: #eeeeee;
  border-radius: 4px;

  &::before {
    transform: translate(-1px, -1px);
    border: 1px solid #000;
    border-radius: 4px;
  }

  &-default {
    &.@{class-prefix-button}-fill-outline {
      background-color: transparent;
      border-color: #333333;
    }
    &.@{class-prefix-button}-fill-none {
      background-color: transparent;
      border-width: 0;
    }
  }

  &:not(&-default) {
    color: #ffffff;
    &.@{class-prefix-button}-fill-outline {
      background-color: transparent;
    }
    &.@{class-prefix-button}-fill-none {
      background-color: transparent;
      border-width: 0;
    }
  }

  &-primary {
    background-color: #1677ff;
    border-color: #1677ff;
    &.@{class-prefix-button}-fill-outline,
    &.@{class-prefix-button}-fill-none {
      color: #1677ff;
    }
  }
  &-success {
    background-color: #00b578;
    border-color: #00b578;
    &.@{class-prefix-button}-fill-outline,
    &.@{class-prefix-button}-fill-none {
      color: #00b578;
    }
  }
  &-danger {
    background-color: #ff3141;
    border-color: #ff3141;
    &.@{class-prefix-button}-fill-outline,
    &.@{class-prefix-button}-fill-none {
      color: #ff3141;
    }
  }
  &-warning {
    background-color: #ff8f1f;
    border-color: #ff8f1f;
    &.@{class-prefix-button}-fill-outline,
    &.@{class-prefix-button}-fill-none {
      color: #ff8f1f;
    }
  }

  &&-mini {
    font-size: 13px;
  }

  &&-small {
    padding-top: 3px;
    padding-bottom: 3px;
    font-size: 15px;
  }
  &&-large {
    padding-top: 11px;
    padding-bottom: 11px;
    font-size: 18px;
  }
  &&-shape-rounded {
    border-radius: 1000px;
    &::before {
      border-radius: 1000px;
    }
  }
  &&-shape-rectangular {
    border-radius: 0;
  }
}

@import (reference) '../style/index.less';

.container {
    .flex-center();
    justify-content: center;
    flex-direction: column;
    @media @mobile {
        flex-direction: column;
    }
    box-shadow: @box-shadow-cover;
    & > a > div {
        transition: @transition-time transform;
    }

    h2 {
      color: #61afef;
    }
    ul > li {
      padding-top:.3em;

    }
  }

.post {
    .flex-center();
    // .frame-small();
    flex-wrap: initial;
    flex-direction: row;
    width: 100%;
    box-sizing: border-box;
    &:hover {
        > div:first-child > a > div {
            transform: scale(1.1) !important
        }
    }
    @media @mobile {
        width: 100%;
        flex-direction: column;
    }
}

.cover {
    overflow: hidden;
    margin: @margin-small;
    width: 40%;
    min-width: 40%;
    & > a > div {
        transition: @transition-time transform;
    }
    @media @mobile {
        min-width: 100%;
        width: 100%;
    }
}

.content {
    // .frame-small();
    // text-align: center;
    h1, h2, p {
    // text-align: center;
        margin: @margin-zero @margin-zero @margin-zero @margin-zero;
        padding-bottom: 20px;
    }
    h2 {
        text-shadow: @text-shadow-title;
    }
    span > Link {
      color: #61afef;
    }
    p {
        .frame-small();
    }
}

.badge {
  color: #61afef;
}

.badge:hover {
  color: #c678dd;

}

.card {
  padding: 1rem;
  margin: 0.7rem 0;
  padding-bottom: 20px;
  background-color: #1e2127;
  box-shadow: @box-shadow-cover;
}
.list {
    .flex-center();
    flex-wrap: nowrap;
    font-size: 1rem;
ul {
    list-style: none;
    .flex-center();
    flex-wrap: nowrap;
    height: 8vh;
    font-size: 1.5em;
    margin: @margin-zero @margin-medium;
    padding: @padding-zero;
    @media @mobile {
        margin-top: @margin-small;
        margin-bottom: @margin-small;
    }
    li {
        margin: @margin-zero @margin-small;
        a {
            // text-transform: uppercase;
            transition: @transition-time color;
            &:hover {
                cursor: pointer;
                color: #c678dd;
            }
        }
    }
}
}


ul.postTags {
  padding: 0;
  display: inline-flex;
  list-style: none;
  justify-content: center;

  li {
    margin-right: 10px;
  justify-content: center;
  }
}

//
// Effects
// -----------------------------------------------------------------------------
//
// ### Usage:
// 提供各种视觉效果的封装。
//

@import "variables.less";
@import "compatibility.less";
@import "util.less";

// ## 文字效果

//
// 文字浮凸效果

.embossed-text(@bg-color) {
    color: lighten(@bg-color, 3%);
}
.embossed-text(@bg-color, @fg-color) {
    color: @fg-color;
}
.embossed-text(...) {
    text-shadow: 0 1px 1px rgba(0, 0, 0, 0.5), 0 -1px 0 rgba(255, 255, 255, 0.5);
}

//
// 文字下陷效果

.debossed-text(@bg-color) {
    @color: darken(@bg-color, 3%);
    color: rgba(red(@color), green(@color), blue(@color), 0.8);
}
.debossed-text(@bg-color, @fg-color) {
    @color: darken(@fg-color, 3%);
    color: rgba(red(@color), green(@color), blue(@color), 0.8);
}
.debossed-text(@bg-color, ...) {
    text-shadow: 0 1px 1px @bg-color, 0 0 0 #000, 0 1px 0 rgba(255, 255, 255, 0.8);
}

//
// 3D文本效果

.3d-text(@color) {
    color: @color;
    text-shadow: 0 1px 0 @color - #272727,
                 0 2px 0 @color - #303030,
                 0 3px 0 @color - #393939,
                 0 4px 0 @color - #424242,
                 0 5px 0 @color - #5b5b5b,
                 0 6px 1px rgba(0, 0, 0, 0.1),
                 0 0 5px rgba(0, 0, 0, 0.1),
                 1px 1px 3px rgba(0, 0, 0, 0.3),
                 3px 3px 5px rgba(0, 0, 0, 0.2),
                 5px 5px 10px rgba(0, 0, 0, 0.25),
                 0 10px 10px rgba(0, 0, 0, 0.2),
                 0 20px 20px rgba(0, 0, 0, 0.15);
}

//
// 文本发光效果

.glow-text(@radius: 5px) when (isnumber(@radius)) {
    text-shadow: 0 0 @radius;
}
.glow-text(@color, @radius: 5px) when (iscolor(@color)) {
    text-shadow: 0 0 @radius @color;
}

//
// 文本模糊效果

.blurry-text(@color, @radius: 0.15em) {
    color: transparent;
    text-shadow: 0 0 @radius @color;
    // 0.1px of spread distance made the shadow visible under IE10
    text-shadow: 0 0 @radius 0.1px @color;
}

//
// Anchors
// --------------------------------------------------
// Anchors show upon hovering over a heading


// PLEASE DON'T CHANGE ANCHOR SIZES without
// Completely understanding what they're doing.
//
// The anchors are used (beyond being anchors)
// to ensure that headings do no overlap with
// the top navbar.
//
// If you feel a need to change heading spacing,
// this is mostl likely not the best place
// to do it.



// allow the container to constrain the width
@anchor-width:              @content-gutter; // see less-docs #203
@anchor-distance:           80px;
@anchor-distance-small:     40px;



// Base class
// ----------------------------------------------
// Our "anchors" are really just icons that sit
// in the left margin, and are only visible when
// hovering over headings or the icons themselves.

.anchor {
  &, &:empty{
    position: absolute;
    top: auto;
    bottom: 0;
    left: 0;

    color: transparent;
    font-size: 18px;
    padding: 10px 10px 10px 25px;
    width: @anchor-width;
  }
}

// Adjust the vertical positioning
// of anchors next to larger headings.

.anchor {
  .adjust(h2);
  .adjust(h3);
  .adjust(h4);

  .adjust(@tag) {
    @{tag} & {
      @tag-font-size: ~'font-size-@{tag}';
      margin-bottom: ceil(((@@tag-font-size - @font-size-h1) * @headings-line-height / 2));
    }
  }
}

// Headings
// ----------------------------------------------

h1, h2, h3 {
  position: relative;
  padding-left: @content-gutter;
  margin-left: -(@content-gutter);

  .anchor:hover {
    color: @gray-darkest;
    visibility: visible;
    text-decoration: none;
  }
}

// anchor targets are invisible anchors for compatibility with
// previous headings and URLs that have been moved or renamed.
h1, h2, h3, .anchor-target {
  scroll-margin-top: @anchor-distance;
}

@import '../custom.less';

@notify-prefix-cls: ~'@{css-prefix}notify';

.@{notify-prefix-cls} {
  @apply fixed;
  @apply ~'z-[1101]';
  @apply ~"max-w-[theme('spacing.108')]";
  @apply w-full;
  @apply box-border;
  @apply transition-all duration-300;
  @apply overflow-hidden;
  @apply whitespace-nowrap;
  @apply p-6;
  @apply rounded-sm;
  @apply text-sm;
  @apply flex;
  @apply flex-row;
  @apply items-start;
  @apply shadow-xl;
  @apply rounded;
  @apply bg-color-bg-1;

  &.top-left {
    @apply ~'left-2.5';
    @apply top-6;
  }

  &.bottom-left {
    @apply ~'left-2.5';
    @apply bottom-6;
  }

  &.top-right {
    @apply ~'right-2.5';
    @apply top-6;
  }

  &.bottom-right {
    @apply ~'right-2.5';
    @apply bottom-6;
  }

  & &__title {
    @apply font-bold;
    @apply text-sm;
    @apply text-color-text-primary;
    @apply ~'leading-6.5';
    @apply whitespace-nowrap;
    @apply overflow-hidden;
    @apply text-ellipsis;
  }

  & &__icon {
    @apply text-color-brand;
  }

  & &__content {
    @apply m-0;
    @apply p-0;
    @apply text-sm;
    @apply text-color-text-primary;
    @apply break-all;
    @apply whitespace-pre-wrap;
  }

  & &__closebtn {
    @apply cursor-pointer;
    @apply text-color-brand;
    @apply absolute;
    @apply ~'top-1/2';
    @apply ~'right-2.5';
    @apply ~'-translate-y-2/4';
  }

  & &__icon-zone {
    @apply w-6;
    @apply h-6;
    @apply text-2xl;
  }

  & &__message-zone {
    @apply w-full;
    @apply ~'ml-2.5';
    @apply min-w-0;
  }

  & &__close-zone {
    @apply w-4;
    @apply h-4;
    @apply text-base;
    @apply cursor-pointer;
  }

  &--info &__icon-zone {
    @apply fill-color-info-primary;
  }

  &--warning &__icon-zone {
    @apply fill-color-warning;
  }

  &--error &__icon-zone {
    @apply fill-color-error;
  }

  &--success &__icon-zone {
    @apply fill-color-success;
  }

  &__icon-zone &__icon-status {
    @apply relative;
    @apply -top-1;
  }

  &--no-close &__message-zone {
    @apply w-full;
  }

  &__message-zone &__title-wrapper {
    @apply h-6;
    @apply leading-6;
    @apply mb-2;
    @apply text-color-text-primary;
  }

  &__message-zone &__content-wrapper {
    @apply h-auto;
    @apply leading-6;
    @apply ~'max-h-[theme(spacing.24)]';
    @apply overflow-y-auto;
  }

  &__close-zone &__icon-close {
    @apply relative;
    @apply ~'top-0.5';
  }

  &--no-icon &__message-zone {
    @apply w-full;
  }
}

@import '../mixins/progress.less';
@import '../custom.less';

@progress-prefix-cls: ~'@{css-prefix}progress';

.@{progress-prefix-cls} {
  @apply relative;
  @apply leading-none;

  &--line {
    @apply flex;
    @apply items-center;
  }

  &.is-success {
    .progress-status(theme('colors.color.success.DEFAULT'));
  }

  &.is-warning {
    .progress-status(theme('colors.color.warning.DEFAULT'));
  }

  &.is-exception {
    .progress-status(theme('colors.color.error.DEFAULT'));
  }

  &__text {
    @apply text-xs;
    @apply text-color-text-primary;
    @apply inline-block;
    @apply align-middle;
    @apply ml-2;
    @apply leading-none;

    i {
      @apply align-middle;
      @apply inline-block;
    }
  }

  &--circle,
  &--dashboard {
    @apply inline-block;

    .@{progress-prefix-cls}__text {
      @apply absolute;
      @apply ~'top-1/2';
      @apply left-0;
      @apply w-full;
      @apply text-center;
      @apply m-0;
      @apply translate-x-0 ~'-translate-y-1/2';

      i {
        @apply align-middle;
        @apply inline-block;
      }
    }
  }

  &--without-text &__text {
    @apply hidden;
  }

  &--without-text &-bar {
    @apply pr-0;
    @apply mr-0;
    @apply block;
  }

  &--text-inside &-bar {
    @apply pr-0;
    @apply mr-0;
  }

  &-bar {
    @apply pr-12;
    @apply w-full;
    @apply -mr-12;
    @apply box-border;

    &__outer {
      @apply ~'h-1.5';
      @apply rounded-full;
      @apply bg-color-bg-3;
      @apply overflow-hidden;
      @apply relative;
      @apply align-middle;
    }

    &__inner {
      @apply absolute;
      @apply left-0;
      @apply top-0;
      @apply h-full;
      @apply bg-color-brand;
      @apply text-right;
      @apply rounded-full;
      @apply leading-none;
      @apply whitespace-nowrap;
      transition: width 0.6s ease;

      &::after {
        @apply content-[''];
        @apply h-full;
      }
    }

    &__innerText {
      @apply text-color-text-inverse;
      @apply text-xs;
      @apply mr-3;
    }

    &,
    &__inner::after,
    &__innerText {
      @apply inline-block;
      @apply align-middle;
    }
  }
}

@-webkit-keyframes progress {
  0% {
    @apply bg-left-top;
  }

  100% {
    background-position: 32px 0;
  }
}

@keyframes progress {
  0% {
    @apply bg-left-top;
  }

  100% {
    background-position: 32px 0;
  }
}

@import '../custom.less';

@popover-prefix-cls: ~'@{css-prefix}popover';
@popper-prefix-cls: ~'@{css-prefix}popper';

.@{popover-prefix-cls}.@{popper-prefix-cls} {
  @apply absolute;
  @apply bg-color-bg-1;
  @apply text-color-icon-primary;
  @apply rounded;
  @apply border-none;
  @apply py-3 px-4;
  @apply ~'z-[2000]';
  @apply ~'leading-5.5';
  @apply text-justify;
  @apply text-sm;
  @apply shadow-md;
  @apply break-all;

  .popper__arrow,
  .popper__arrow::after {
    @apply absolute;
    @apply block;
    @apply w-0;
    @apply h-0;
    @apply border-transparent;
    @apply border-solid;
  }

  .popper__arrow,
  .@{popper-prefix-cls} .popper__arrow {
    @apply border-4;
  }

  .popper__arrow::after {
    @apply ~"content-['']";
  }

  &[x-placement^='top'] {
    @apply mb-3;

    .popper__arrow {
      @apply -bottom-1;
      @apply ~'left-1/2';
      margin-right: 3px;
      @apply border-solid;
      @apply border-b-color-bg-1;
      @apply border-l-color-bg-1;
      @apply rounded-bl-sm;
      transform: rotate(315deg);
    }
  }

