  @media (prefers-color-scheme: dark) {
    .wx-root:not([data-weui-theme='light']) &,
    body:not([data-weui-theme='light']) & {
      @darkRule();
    }
  }
}

//
// Retina Borders
// ------------------------------

// top

.retina-1px-border-top(@color) {
	position: relative;

	&::after {
		.size(100%,1px);
		background-color: @color;
		top: -1px;
		content: " ";
		left: 0;
		position: absolute;
	}

	// simulate a 1px border on retina screens
	@media (-webkit-min-device-pixel-ratio: 2) {
		&::after {
			.scaleY(0.5);
			.transform-origin(0 0);
		}
	}
}

// left

.retina-1px-border-left(@color) {
	position: relative;

	&::after {
		background-color: @color;
		bottom: 0;
		content: " ";
		left: 0;
		position: absolute;
		top: 0;
		width: 1px;
	}

	// simulate a 1px border on retina screens
	@media (-webkit-min-device-pixel-ratio: 2) {
		&::after {
			.scaleX(0.5);
			.transform-origin(0 0);
		}
	}
}

// bottom

.retina-1px-border-bottom(@color) {
	position: relative;

	&::after {
		.size(100%,1px);
		background-color: @color;
		bottom: -1px;
		content: " ";
		left: 0;
		position: absolute;
	}

	// simulate a 1px border on retina screens
	@media (-webkit-min-device-pixel-ratio: 2) {
		&::after {
			.scaleY(0.5);
			.transform-origin(0 0);
		}
	}
}

// right

.retina-1px-border-right(@color) {
	position: relative;

	&::after {
		.size(1px,100%);
		background-color: @color;
		right: 0;
		content: " ";
		right: 0;
		position: absolute;
	}

	// simulate a 1px border on retina screens
	@media (-webkit-min-device-pixel-ratio: 2) {
		&::after {
			.scaleX(0.5);
			.transform-origin(0 0);
		}
	}
}

// top and bottom

.retina-1px-border-top-and-bottom(@color) {
	position: relative;

	&::after,
	&::before {
		.size(100%,1px);
		background-color: @color;
		content: " ";
		left: 0;
		position: absolute;
	}
	&::before {
		top: -1px;
	}
	&::after {
		bottom: -1px;
	}

	// simulate a 1px border on retina screens
	@media (-webkit-min-device-pixel-ratio: 2) {
		&::after,
		&::before {
			.scaleY(0.5);
		}
		&::before {
			.transform-origin(0 bottom);
		}
		&::after {
			.transform-origin(0 top);
		}
	}
}

//
// Alertbar
// ==============================


// base

.Alertbar {
	.translateZ(0); // stop re-paint when introduced into the DOM
	.transition( background-color 160ms ); // animate variant if state changed while visible
	color: white;
	font-size: @font-size-sm;
	left: 0;
	line-height: 1.1;
	padding: @gutter-sm;
	text-align: center;
	top: 0;
	width: 100%;
	z-index: @zindex-alertbar;
}


// overlay translucent for pulse

.Alertbar--pulse::after {
	.animation( pulse 2s linear infinite );
	.fill-space();
	background-color: black;
	content: "";
	opacity: 0;
	z-index: 1;
}


// sit the text above the pulsing background

.Alertbar__inner {
	position: relative;
	z-index: 2;
}


// variants

.Alertbar--danger   { background-color: @app-danger; }
.Alertbar--default  { background-color: @gray-light; }
.Alertbar--info     { background-color: @app-info; }
.Alertbar--primary  { background-color: @app-primary; }
.Alertbar--success  { background-color: @app-success; }
.Alertbar--warning  { background-color: @app-warning; }




// Animation
// ------------------------------


// prepare for animation

.Alertbar--animated {
	margin: 0;
	position: absolute;
}


// apply animation

.Alertbar-enter {
	.animation( alertbarEnter 240ms @view-transition-timing-function );
}
.Alertbar-leave {
	.animation( alertbarLeave 240ms @view-transition-timing-function );
}

// slide up

@-webkit-keyframes alertbarEnter {
	from {-webkit-transform: translate3d(0, -100%, 0); opacity: .5; }
	to { -webkit-transform: none; opacity: 1; }
}
@keyframes alertbarEnter {
	from {transform: translate3d(0, -100%, 0); opacity: .5; }
	to { transform: none; opacity: 1; }
}

// slide down

@-webkit-keyframes alertbarLeave {
	from { -webkit-transform: none; opacity: 1; }
	to { -webkit-transform: translate3d(0, -100%, 0); opacity: .5; }
}
@keyframes alertbarLeave {
	from { transform: none; opacity: 1; }
	to {transform: translate3d(0, -100%, 0); opacity: .5; }
}

