	}

	.editor-container {
		margin: @ui-padding 0;
	}

	.form-control {
		font-size: @ui-size*1.25;
		height: @ui-line-height;
		padding-top: 0;
		padding-bottom: 0;
	}

	select.form-control:focus {
		background-color : @ui-bg;

	}
	.update-all-button {
		font-size: .75em;
	}

	.search-container .btn {
		font-size: @ui-input-size;
	}

}

@keyframes van-slide-up-enter {
  from {
    transform: translate3d(0, 100%, 0);
  }
}

@keyframes van-slide-up-leave {
  to {
    transform: translate3d(0, 100%, 0);
  }
}

@keyframes van-slide-down-enter {
  from {
    transform: translate3d(0, -100%, 0);
  }
}

@keyframes van-slide-down-leave {
  to {
    transform: translate3d(0, -100%, 0);
  }
}

@keyframes van-slide-left-enter {
  from {
    transform: translate3d(-100%, 0, 0);
  }
}

@keyframes van-slide-left-leave {
  to {
    transform: translate3d(-100%, 0, 0);
  }
}

@keyframes van-slide-right-enter {
  from {
    transform: translate3d(100%, 0, 0);
  }
}

@keyframes van-slide-right-leave {
  to {
    transform: translate3d(100%, 0, 0);
  }
}

@keyframes van-fade-in {
  from {
    opacity: 0;
  }

  to {
    opacity: 1;
  }
}

@keyframes van-fade-out {
  from {
    opacity: 1;
  }

  to {
    opacity: 0;
  }
}

@keyframes van-rotate {
  from {
    transform: rotate(0deg);
  }

  to {
    transform: rotate(360deg);
  }
}

.van-fade {
  &-enter-active {
    animation: var(--van-duration-base) van-fade-in both var(--van-ease-out);
  }

  &-leave-active {
    animation: var(--van-duration-base) van-fade-out both var(--van-ease-in);
  }
}

.van-slide-up {
  &-enter-active {
    animation: van-slide-up-enter var(--van-duration-base) both
      var(--van-ease-out);
  }

  &-leave-active {
    animation: van-slide-up-leave var(--van-duration-base) both
      var(--van-ease-in);
  }
}

.van-slide-down {
  &-enter-active {
    animation: van-slide-down-enter var(--van-duration-base) both
      var(--van-ease-out);
  }

  &-leave-active {
    animation: van-slide-down-leave var(--van-duration-base) both
      var(--van-ease-in);
  }
}

.van-slide-left {
  &-enter-active {
    animation: van-slide-left-enter var(--van-duration-base) both
      var(--van-ease-out);
  }

  &-leave-active {
    animation: van-slide-left-leave var(--van-duration-base) both
      var(--van-ease-in);
  }
}

.van-slide-right {
  &-enter-active {
    animation: van-slide-right-enter var(--van-duration-base) both
      var(--van-ease-out);
  }

  &-leave-active {
    animation: van-slide-right-leave var(--van-duration-base) both
      var(--van-ease-in);
  }
}
